+// --- Resource with version and tags ---
+
+/// Versioned resource with tags.
+#[resource(uri = "data://metrics", version = "3.0.0", tags = ["monitoring", "metrics"])]
+fn metrics_resource(_ctx: &McpContext) -> String {
+    r#"{"cpu": 42}"#.to_string()
+}
+
+#[test]
